import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';

const EditBlogPage = () => {
  const { id } = useParams();
  const navigate = useNavigate();

  const [title, setTitle] = useState('');
  const [content, setContent] = useState('');
  const [categoryId, setCategoryId] = useState('');

  useEffect(() => {
    // Fetch blog by ID and pre-fill form
    axios.get(`http://localhost:5000/api/blogs/${id}`)
      .then(res => {
        const blog = res.data;
        setTitle(blog.title);
        setContent(blog.content);
        setCategoryId(blog.category_id);
      })
      .catch(err => {
        console.error('Error fetching blog:', err);
        alert('Blog not found or server error.');
      });
  }, [id]);

  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      await axios.put(`http://localhost:5000/api/blogs/${id}/edit`, {
        title,
        content,
        category_id: categoryId,
        image_url: 'https://via.placeholder.com/600x400.png?text=Updated+Image', // Optional
        user_id: 1 // Replace with logged-in user ID
      });

      navigate('/');
    } catch (error) {
      console.error('Error updating blog:', error);
      alert('Failed to update blog.');
    }
  };

  return (
    <div className="max-w-3xl mx-auto p-4 bg-white rounded shadow mt-8">
      <h2 className="text-2xl font-semibold mb-6">Edit Blog</h2>
      <form onSubmit={handleSubmit} className="space-y-4">
        <input
          type="text"
          placeholder="Blog Title"
          value={title}
          onChange={(e) => setTitle(e.target.value)}
          className="w-full p-2 border rounded"
          required
        />
        <textarea
          placeholder="Blog Content"
          value={content}
          onChange={(e) => setContent(e.target.value)}
          className="w-full p-2 border rounded h-40"
          required
        />
        <input
          type="text"
          placeholder="Category ID"
          value={categoryId}
          onChange={(e) => setCategoryId(e.target.value)}
          className="w-full p-2 border rounded"
          required
        />
        <button type="submit" className="bg-yellow-500 text-white px-4 py-2 rounded hover:bg-yellow-600">
          Update Blog
        </button>
      </form>
    </div>
  );
};

export default EditBlogPage;
